# 视频解析模块 - 快速开始

## 1. 最简单的使用方式

```kotlin
// 在 Activity 或 Fragment 中
val helper = VideoDownloadHelper(context)

lifecycleScope.launch {
    try {
        // 解析视频
        val videoInfo = helper.parseVideo("https://www.bilibili.com/video/BV1xx411c7mD")

        // 打印视频信息
        Log.d(TAG, helper.formatVideoInfo(videoInfo))

        // 下载视频（自动选择推荐格式）
        val outputDir = File(getExternalFilesDir(null), "downloads")
        val file = helper.downloadVideo(
            url = "https://www.bilibili.com/video/BV1xx411c7mD",
            outputDir = outputDir,
            onProgress = { progress ->
                Log.d(TAG, "下载进度: ${progress.percentage}%")
            }
        )

        Log.d(TAG, "下载完成: ${file.absolutePath}")
    } catch (e: Exception) {
        Log.e(TAG, "错误: ${e.message}")
    }
}
```

## 2. 在 Compose 中使用

### 添加导航路由

在 `MainActivity.kt` 中添加路由：

```kotlin
NavHost(navController = navController, startDestination = "home") {
    composable("home") { HomeScreen(navController) }
    composable("parser") { VideoParserScreen() }  // 添加这行
    // ... 其他路由
}
```

### 添加导航按钮

在 `HomeScreen.kt` 中添加按钮：

```kotlin
Button(
    onClick = { navController.navigate("parser") },
    modifier = Modifier.fillMaxWidth()
) {
    Text("视频解析")
}
```

## 3. 测试解析功能

在 `MainActivity.kt` 的 `onCreate` 中添加测试代码：

```kotlin
override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)

    // 测试视频解析
    lifecycleScope.launch {
        testVideoParser()
    }

    setContent {
        // ... 你的 Compose 内容
    }
}

private suspend fun testVideoParser() {
    val helper = VideoDownloadHelper(this)

    try {
        // 测试 B站
        Log.d(TAG, "测试 B站 解析...")
        val bilibiliInfo = helper.parseVideo("https://www.bilibili.com/video/BV1xx411c7mD")
        Log.d(TAG, helper.formatVideoInfo(bilibiliInfo))

        // 测试 YouTube
        Log.d(TAG, "测试 YouTube 解析...")
        val youtubeInfo = helper.parseVideo("https://www.youtube.com/watch?v=dQw4w9WgXcQ")
        Log.d(TAG, helper.formatVideoInfo(youtubeInfo))

    } catch (e: Exception) {
        Log.e(TAG, "测试失败", e)
    }
}
```

## 4. 常用代码片段

### 仅获取视频信息（不下载）

```kotlin
val helper = VideoDownloadHelper(context)
val videoInfo = helper.parseVideo(url)

// 访问视频信息
val title = videoInfo.title
val duration = videoInfo.duration
val thumbnail = videoInfo.thumbnailUrl
val formats = videoInfo.formats
```

### 选择特定画质下载

```kotlin
val helper = VideoDownloadHelper(context)
val videoInfo = helper.parseVideo(url)

// 选择 720p
val format = videoInfo.formats.firstOrNull { it.quality.contains("720") }
    ?: videoInfo.formats.first()

// 下载
val file = helper.downloadVideo(videoInfo, format, outputDir) { progress ->
    println("进度: ${progress.percentage}%")
}
```

### 获取所有可用画质

```kotlin
val helper = VideoDownloadHelper(context)
val videoInfo = helper.parseVideo(url)

videoInfo.formats.forEach { format ->
    println("${format.quality} - ${format.ext} - ${format.fileSize?.let { formatFileSize(it) }}")
}
```

### 监听详细下载进度

```kotlin
helper.downloadVideo(videoInfo, format, outputDir) { progress ->
    when (progress.status) {
        DownloadProgress.Status.DOWNLOADING -> {
            val percent = progress.percentage
            val downloaded = formatFileSize(progress.bytesDownloaded)
            val total = formatFileSize(progress.totalBytes)
            val speed = formatSpeed(progress.speed)
            println("下载中: $percent% ($downloaded / $total) 速度: $speed")
        }
        DownloadProgress.Status.MERGING -> {
            println("正在合并音视频...")
        }
        DownloadProgress.Status.COMPLETED -> {
            println("下载完成!")
        }
        DownloadProgress.Status.FAILED -> {
            println("下载失败")
        }
    }
}
```

## 5. 错误处理

```kotlin
try {
    val videoInfo = helper.parseVideo(url)
    // ... 处理视频信息
} catch (e: ParserException) {
    // 解析错误
    when {
        e.message?.contains("不支持") == true -> {
            // 不支持的平台
        }
        e.message?.contains("地区限制") == true -> {
            // 地区限制
        }
        else -> {
            // 其他解析错误
        }
    }
} catch (e: Exception) {
    // 网络错误或其他错误
}
```

## 6. 支持的 URL 格式

### B站

```kotlin
// 完整 URL
"https://www.bilibili.com/video/BV1xx411c7mD"

// 短链接
"https://b23.tv/xxxxx"

// BV 号
"BV1xx411c7mD"

// AV 号
"av170001"
```

### YouTube

```kotlin
// 完整 URL
"https://www.youtube.com/watch?v=dQw4w9WgXcQ"

// 短链接
"https://youtu.be/dQw4w9WgXcQ"

// 视频 ID
"dQw4w9WgXcQ"

// 嵌入链接
"https://www.youtube.com/embed/dQw4w9WgXcQ"
```

## 7. 性能优化建议

### 缓存视频信息

```kotlin
class VideoCache {
    private val cache = mutableMapOf<String, VideoInfo>()

    suspend fun getVideoInfo(url: String, helper: VideoDownloadHelper): VideoInfo {
        return cache.getOrPut(url) {
            helper.parseVideo(url)
        }
    }
}
```

### 使用 WorkManager 管理下载

```kotlin
class DownloadWorker(context: Context, params: WorkerParameters) : CoroutineWorker(context, params) {
    override suspend fun doWork(): Result {
        val url = inputData.getString("url") ?: return Result.failure()

        val helper = VideoDownloadHelper(applicationContext)

        return try {
            val outputDir = File(applicationContext.getExternalFilesDir(null), "downloads")
            helper.downloadVideo(url, outputDir)
            Result.success()
        } catch (e: Exception) {
            Result.failure()
        }
    }
}

// 使用
val workRequest = OneTimeWorkRequestBuilder<DownloadWorker>()
    .setInputData(workDataOf("url" to videoUrl))
    .build()

WorkManager.getInstance(context).enqueue(workRequest)
```

## 8. 调试技巧

### 启用详细日志

在 `BilibiliParser.kt` 和 `YouTubeParser.kt` 中，日志标签为 `BilibiliParser` 和 `YouTubeParser`。

在 Android Studio 中过滤日志：

```
tag:BilibiliParser OR tag:YouTubeParser OR tag:VideoDownloadService
```

### 测试不同画质

```kotlin
videoInfo.formats.forEach { format ->
    Log.d(TAG, "测试格式: ${format.quality}")
    try {
        val file = helper.downloadVideo(videoInfo, format, outputDir)
        Log.d(TAG, "成功: ${file.length()} bytes")
    } catch (e: Exception) {
        Log.e(TAG, "失败: ${e.message}")
    }
}
```

## 9. 常见问题

**Q: 下载的视频没有声音？**

A: 高清视频（1080P+）通常使用 DASH 格式，音视频分离。`VideoDownloadHelper` 会自动处理，确保使用它而不是直接调用 `VideoDownloadService`。

**Q: 解析速度慢？**

A: 第一次解析需要请求 API，建议缓存结果。可以使用上面的 `VideoCache` 示例。

**Q: 如何获取最高画质？**

```kotlin
val bestFormat = videoInfo.formats.maxByOrNull { it.height ?: 0 }
```

**Q: 如何只下载音频？**

```kotlin
val audioFormat = helper.getRecommendedAudioFormat(videoInfo)
if (audioFormat != null) {
    // 直接下载音频 URL
    // 注意：需要自己实现音频下载逻辑
}
```

## 10. 下一步

- 查看 `VIDEO_PARSER_README.md` 了解完整文档
